import {saveAs} from 'file-saver';

/**
 * Saves text to an HTML file. This works in either a browser or Electron
 * context.
 */
export function saveHtml(source: string, filename: string) {

    let exportedHtml = source;

    { // scramble contents -----------------------------------------------------------------------
        let scrambled = "";
        const key = 3;
        for (let i = 0; i < exportedHtml.length; i++) {
            scrambled += String.fromCharCode(exportedHtml.charCodeAt(i) ^ key);
        }
        exportedHtml = "TRANSPORT_SCRAMBLE__" + btoa(unescape(encodeURIComponent(scrambled)))
    } // -----------------------------------------------------------------------------------------

    // save back to DF
    const csrfToken: string = window.localStorage.getItem("twee-csrfToken") as string;
    const postUrl: string = window.localStorage.getItem("twee-postUrlHTML") as string;
    if(csrfToken && postUrl) {
        fetch(postUrl, {
            method: "POST",
            mode: "cors",
            cache: "no-cache",
            credentials: "same-origin",
            headers: {
                "Content-Type": "text/plain;charset=UTF-8",
                "Csrf-Token": csrfToken
            },
            referrerPolicy: "no-referrer",
            body: exportedHtml
        });
    }

    // const data = new Blob([source], {type: 'text/html;charset=utf-8'});
	// saveAs(data, filename);
}

/**
 * Saves text to a Twee file. This works in either a browser or Electron
 * context.
 */
export function saveTwee(source: string, filename: string) {
	const data = new Blob([source], {type: 'text/plain;charset=utf-8'});

	saveAs(data, filename);
}
